    int add(int x, int y);
}

#endifadd.cpp#include "add.h"

namespace BasicMath
{
    // define the function add() inside namespace BasicMath
    int add(int x, int y)
    {
        return x + y;
    }
}main.cpp#include "add.h" // for BasicMath::add()

