    {
        return x + y;
    }
}

int main()
{
    namespace Active = Foo::Goo; // active now refers to Foo::Goo

    std::cout << Active::add(1, 2) << '\n'; // This is really Foo::Goo::add()

    return 0;
} // The Active alias ends hereOne nice advantage of namespace aliases: If you ever want to move the functionality withinFoo::Gooto a different place, you can just update theActivealias to reflect the new destination, rather than having to find/replace every instance ofFoo::Goo.#include <iostream>

